 1→import React, { Children, useState } from 'react';
 2→import { FlatList } from 'react-native';
 3→
 4→import {
 5→  isAllowedComponent,
 6→  isReactElement,
 7→} from '../../../utils/validadetype';
 8→import { Box } from '../../atoms/Box';
 9→import { SeparatorHorizontal } from '../../atoms/Spacing';
10→import useCardOptionDrag from './index';
11→import { PropsCardOptionDragGroup } from './Models';
12→import { CardOptionDrag } from './view';
13→
14→function CardOptionDragGroup({
15→  mt,
16→  mb,
17→  ml,
18→  mr,
19→  testID,
20→  children,
21→  refComponent,
22→  disabled,
23→  openedIndex,
24→  onPress,
25→  onMomentumScrollBegin,
26→  onMomentumScrollEnd,
27→  onScrollBeginDrag,
28→  onScrollEndDrag,
29→  onEndReached,
30→  onEndReachedThreshold,
31→  ListFooterComponent,
32→}: PropsCardOptionDragGroup) {
33→  const [scrollEnabled, setScrollEnabled] = useState(true);
34→  const { cloneWithProps } = useCardOptionDrag({ children });
35→  const clonedChildren = cloneWithProps(children, {
36→    onPress,
37→    disabled,
38→  });
39→
40→  const itemSeparator = () => {
41→    return (
42→      <SeparatorHorizontal
43→        width="100%"
44→        height={1}
45→        bgColor="BRAND_COMPLEMENT_02"
46→      />
47→    );
48→  };
49→
50→  return (
51→    <Box testID={testID} width="100%" mt={mt} mb={mb} ml={ml} mr={mr}>
52→      <FlatList
53→        ref={refComponent}
54→        onMomentumScrollBegin={onMomentumScrollBegin}
55→        onMomentumScrollEnd={onMomentumScrollEnd}
56→        onScrollBeginDrag={onScrollBeginDrag}
57→        onScrollEndDrag={onScrollEndDrag}
58→        onEndReached={onEndReached}
59→        scrollEnabled={scrollEnabled}
60→        onEndReachedThreshold={onEndReachedThreshold}
61→        ListFooterComponent={ListFooterComponent}
62→        data={Children.toArray(clonedChildren)}
63→        showsVerticalScrollIndicator={false}
64→        ItemSeparatorComponent={itemSeparator}
65→        contentContainerStyle={{
66→          width: '100%',
67→        }}
68→        renderItem={({ item, index }) =>
69→          isReactElement(item) &&
70→          isAllowedComponent(
71→            (item.type as unknown as { displayName: string }).displayName,
72→            'CardOptionDragComponent',
73→          ) ? (
74→            <Box width="100%" key={index.valueOf()} direction>
75→              <CardOptionDrag
76→                {...item.props}
77→                closeCard={openedIndex !== index}
78→                isMoving={(value) => setScrollEnabled(!value)}
79→              />
80→            </Box>
81→          ) : null
82→        }
83→      />
84→    </Box>
85→  );
86→}
87→
88→export default CardOptionDragGroup;
